const parshaCard = {
  name: "Parsha Noach (Bereshit)",
  questions: [
    {
      question: "What were the names of Noah's three sons?",
      answer: "Shem, Cham, Yefet",
      zchut: 50,
    },
    {
      question: "What day did the rain start?",
      answer: "The 17th of Cheshvan",
      zchut: 50,
    },
    {
      question: "How does the dove represent Israel and the exile?",
      answer: "If it found a place to rest, it would not return (Zohar)",
      zchut: 50,
    },
  ],
  bonus: "If you get all three you can pick a Har HaBayit card"
};
// Extracted TorahPoly Board Buttons and Functions
// This file contains the four special deck buttons (Har Habayit, Parsha, Mazal, Tzadik), their functions, and their placement on the game board.

import React from "react";

// Card data


const bereshitCard = {
  name: "Bereshit",
  questions: [
    {
      question: "What day was Adam born?",
      answer: "The 6th day",
      points: 20,
    },
    {
      question: "What day was not 'good' but 'very' good?",
      answer: "The 6th day",
      points: 20,
    },
    {
      question: "Where do we see adding is sometimes subtracting?",
      answer:
        "Adam added 'don't touch' the tree. The snake used this to fool Chava.",
      points: 20,
    },
  ],
};

const harHaBayitCard = {
  name: "Har HaBayit",
  questions: [
    {
      question: 'Which items were housed in the Kodesh ("holy") chamber?',
      answer: "The showbread table, menorah, and incense altar",
      points: 300,
    },
    {
      question:
        "What is the OJ associated with the Omer, the Two Loaves and the Lechem Hapanim?",
      answer: `That never was a disqualifying defect found in any of these 3 holy offerings. Explanation: \na. The Omer, the barley offering brought on the 16th of Nissan, released the new crop for eating if a defect occurred, they wouldn't be able to bring the offering on that day and the new crop would have remained forbidden for the entire year!\nb. If there was a defect in the Two Loaves brought on Shavuos, we would have been unable to bring this offering, and would then have been unable to use the new wheat crop for minchah on the mizbe'ach.\nc. If a defect were found on the 12 loaves of the Lechem HaPanim that were baked before Shabbos, no new loaves would have been able to be set on the Shulchan until the following week.`,
      points: 600,
    },
  ],
};


const mazalCards = [
  {
    name: "Mazal",
    text: `You had a dream of buried treasure in a far-off city. You travelled there and found the spot and began digging. A policeman stopped you, and after you explained the story, he said he had the same dream of a treasure buried under the floorboards of a tailor shop. You realized that he was describing your own house. You dropped the shovel and ran home to discover the treasure buried under your own bed.`,
    reward: 1000,
    rewardType: "money",
  },
  {
    name: "Mazal",
    text: `You were first in line to marry Ruth the righteous Moabite convert. You declined because you were concerned about your yichus (pedigree). Your cousin Boaz married her instead. You're concern for your good name is recorded in the Torah. You are remembered as Plony Almony (or in English - Joe Blow). That righteous Moabite convert became the grandmother of King David. You thought you were concerned about your zchut but ended up losing zchut big time. Pay 500 zchut to the Tzedaka fund.`,
    penalty: 500,
    penaltyType: "zchut",
    target: "tzedakah",
    buttonText: "Pay 500 Zchut (Tzedaka Fund)",
  },
];

const tzadikCard = {
  name: "Tzadik",
  questions: [
    {
      question: "From where does Rebbi Avahu learn that it is better to be the pursued than the pursuer?",
      answer: "Rebbi Avahu learns that it is better to be the pursued than the pursuer from the pigeon and the young dove, who are pursued more than any other birds, and who are therefore the only birds who have the merit to be brought on the Mizbe'ach. (Bava Kama 93)",
      zchut: 1000,
    },
    {
      question: "Rabbi Yehuda, says to be vigilant with regard to treating with respect the children of unlearned parents, as from some of them Torah will emerge, Why is that?",
      answer: "Because they don’t have the rudiments others might have, they work harder to achieve Torah and this resilience is an important quality of greatness. They may become leaders and agents of change. Some who have been spoon-fed may not always have it (Sanhedrin 96)",
      zchut: 2000,
    },
  ],
};

// Button placement and rendering
export function TorahPolyBoardButtons({ startQA, onShuffleParsha, onReturnParsha, tzedakahAmount }) {
  return (
    <>
      {/* Mazal Deck Button */}
      <button
        onClick={() => startQA(mazalCards[0])} // For now, use the first Mazal card
        style={{
          position: "absolute",
          top: "20%",
          left: "38%",
          transform: "translate(-50%, -50%)",
          padding: "6px 12px",
          fontSize: 14,
          backgroundColor: "#28a745",
          color: "#fff",
          border: "2px solid #000",
          borderRadius: 6,
          cursor: "pointer",
        }}
      >
        Mazal Deck
      </button>

      {/* Har HaBayit Deck Button */}
      <button
        onClick={() => startQA(harHaBayitCard)}
        style={{
          position: "absolute",
          top: "20%",
          left: "62%",
          transform: "translate(-50%, -50%)",
          padding: "6px 12px",
          fontSize: 14,
          backgroundColor: "#6f42c1",
          color: "#fff",
          border: "2px solid #000",
          borderRadius: 6,
          cursor: "pointer",
        }}
      >
        Har HaBayit Deck
      </button>

      {/* Tzadik Deck Button */}
      <button
        onClick={() => startQA(tzadikCard)}
        style={{
          position: "absolute",
          top: "43%",
          left: "54%",
          transform: "translate(-50%, -50%)",
          padding: "6px 12px",
          fontSize: 14,
          backgroundColor: "#ffc107",
          color: "#000",
          border: "2px solid #333",
          borderRadius: 6,
          cursor: "pointer",
        }}
      >
        Tzadik Deck
      </button>

      {/* Parsha Deck Button */}
      <button
        onClick={() => startQA(parshaCard)}
        style={{
          position: "absolute",
          top: "58%",
          left: "70%",
          transformOrigin: "left center",
          transform: "translate(-50%, -50%) rotateX(40deg)",
          padding: "6px 12px",
          fontSize: 14,
          backgroundColor: "#17a2b8",
          color: "#fff",
          border: "2px solid #000",
          borderRadius: 6,
          cursor: "pointer",
        }}
      >
        Parsha Deck
      </button>

      {/* Tzedakah Fund Display */}
      <div
        style={{
          position: "absolute",
          top: "69.5%",
          left: "26.5%",
          transformOrigin: "left center",
          transform: "translate(-50%, -50%) rotate(48deg)",
          backgroundColor: "#f7e600",
          color: "#333",
          border: "2px solid #bfa800",
          borderRadius: 10,
          padding: "8px 18px",
          fontWeight: "bold",
          fontSize: 16,
          boxShadow: "0 2px 8px #aaa",
          zIndex: 2,
        }}
      >
        Tzedakah: ${tzedakahAmount || 0}
      </div>

      {/* Zchut Fund Button (test position) */}
      <div
        style={{
          position: "absolute",
          top: "55%", // move up toward square 10
          left: "29%", // move right toward square 10
          transformOrigin: "left center",
          transform: "translate(-50%, -50%) rotate(48deg)",
          backgroundColor: "#e0e0e0",
          color: "#333",
          border: "2px solid #888",
          borderRadius: 10,
          padding: "8px 18px",
          fontWeight: "bold",
          fontSize: 16,
          boxShadow: "0 2px 8px #aaa",
          zIndex: 2,
        }}
      >
        Zchut Fund (test)
      </div>

      {/* Shuffle Button */}
      <div
        style={{
          position: "absolute",
          top: "70%",
          left: "73%",
          display: "flex",
          flexDirection: "row",
          gap: "18px",
          transformOrigin: "right center",
          transform: "translate(-50%, -50%) rotate(-46deg)",
        }}
      >
        <button
          onClick={onShuffleParsha}
          style={{
            padding: "4px 10px",
            fontSize: 12,
            backgroundColor: "#ff9800",
            color: "#fff",
            border: "2px solid #000",
            borderRadius: 8,
            cursor: "pointer",
            boxShadow: "0 2px 8px #aaa",
          }}
        >
          Shuffle
        </button>
        <button
          onClick={onReturnParsha}
          style={{
            padding: "4px 10px",
            fontSize: 12,
            backgroundColor: "#007bff",
            color: "#fff",
            border: "2px solid #000",
            borderRadius: 8,
            cursor: "pointer",
            boxShadow: "0 2px 8px #aaa",
          }}
        >
          Return
        </button>
      </div>
    </>
  );
}

// Export card data for use elsewhere
export { bereshitCard, harHaBayitCard, mazalCards, tzadikCard, parshaCard };
